"use client";

import { useEffect, useState } from "react";
import Topbar2 from "@/components/headers/Topbar2";
import Header12 from "@/components/headers/Header12";
import Footer2 from "@/components/footers/Footer2";
import ScrollTop from "@/components/common/ScrollTop";
import { EmailValidator } from "@/components/tools/EmailValidator";
import WhyItMattersSection from "@/components/tools/WhyItMattersSection";
import InterpretationTiles from "@/components/tools/InterpretationTiles";
import HighlightedTextBox from "@/components/tools/HighlightedTextBox";
import FAQAccordion from "@/components/tools/FAQAccordion";

export default function EmailValidatorClient() {
  const [currentTool, setCurrentTool] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetch("/data/toolPages.json")
      .then((res) => res.json())
      .then((data) => {
        const tool = data.toolPages.find((t) => t.pageName === "email-validator");
        setCurrentTool(tool);
        setLoading(false);
      })
      .catch((err) => {
        console.error("Error loading toolPages.json:", err);
        setLoading(false);
      });

    window.scrollTo(0, 0);
  }, []);

  if (loading) {
    return <div style={{ textAlign: "center", padding: "100px 20px" }}>Loading...</div>;
  }

  if (!currentTool) {
    return <div style={{ textAlign: "center", padding: "100px 20px" }}>Tool not found</div>;
  }

  return (
    <>
      <Topbar2 bgColor="bg_blue-6" />
      <Header12 />

      {/* HERO SECTION */}
      <section className="tf-page-title">
        <div className="container-full">
          <div className="heading-title pb_70 pt_70">
            <div className="row">
              <div className="col-12">
                <div className="page-title-heading text-center">
                  <div className="heading text-center">{currentTool?.heading}</div>
                  <p className="text-center text_2 text_black-2 mt_5">
                    Instantly verify email addresses and reduce bounce rates
                  </p>
                </div>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* TOOL COMPONENT SECTION */}
      <section className="flat-spacing-4">
        <div className="container">
          <div className="row">
            <EmailValidator />
          </div>
        </div>
      </section>

      {/* WHY IT MATTERS SECTION */}
      <section className="flat-spacing-4">
        <div className="container">
          <div className="row">
            <div className="col-12">
              <WhyItMattersSection pageName="email-validator" />
            </div>
          </div>
        </div>
      </section>

      {/* HIGHLIGHTED BOX SECTION */}
      <section className="flat-spacing-4">
        <div className="container">
          <div className="row">
            <div className="col-12">
              <HighlightedTextBox pageName="email-validator" />
            </div>
          </div>
        </div>
      </section>

      {/* UNDERSTANDING SECTION */}
      <section className="flat-spacing-4">
        <div className="container">
          <div className="row mb_50">
            <div className="col-12">
              <h2 className="heading text-center mb_50">Understanding Email Validator</h2>
            </div>
          </div>
          <div className="row">
            <div className="col-12">
              <p className="text text_black-2" style={{ fontSize: "16px", lineHeight: "1.8" }}>
                {currentTool?.whatIsContent}
              </p>
            </div>
          </div>
        </div>
      </section>

      {/* HOW EMAIL VALIDATION WORKS - InterpretationTiles */}
      <section className="flat-spacing-4">
        <div className="container">
          <div className="row">
            <div className="col-12">
              <InterpretationTiles pageName="email-validator" />
            </div>
          </div>
        </div>
      </section>

      {/* HOW TO USE & APPLICATIONS */}
      <section className="flat-spacing-4">
        <div className="container">
          <div className="row mb_50">
            <div className="col-lg-6">
              <h3 className="heading-h3 mb_30">How to Use This Tool</h3>
              <ol style={{ paddingLeft: "20px" }}>
                <li style={{ marginBottom: "15px" }} className="text_2 text_black-2">
                  Enter or paste an email address into the input field.
                </li>
                <li style={{ marginBottom: "15px" }} className="text_2 text_black-2">
                  Click the "Validate" button to analyze the email.
                </li>
                <li style={{ marginBottom: "15px" }} className="text_2 text_black-2">
                  Instantly see validation results and any issues found.
                </li>
                <li style={{ marginBottom: "15px" }} className="text_2 text_black-2">
                  Review suggestions for fixing invalid email formats.
                </li>
                <li className="text_2 text_black-2">
                  Use the results to clean your email lists and improve deliverability.
                </li>
              </ol>
            </div>

            <div className="col-lg-6">
              <h3 className="heading-h3 mb_30">Business Applications</h3>
              <ul style={{ paddingLeft: "20px" }}>
                <li style={{ marginBottom: "15px" }} className="text_2 text_black-2">
                  <strong>Email List Cleaning:</strong> Remove invalid emails from your mailing lists
                </li>
                <li style={{ marginBottom: "15px" }} className="text_2 text_black-2">
                  <strong>Campaign Accuracy:</strong> Ensure emails reach real, valid addresses
                </li>
                <li style={{ marginBottom: "15px" }} className="text_2 text_black-2">
                  <strong>Bounce Rate Reduction:</strong> Lower your email bounce rates significantly
                </li>
                <li style={{ marginBottom: "15px" }} className="text_2 text_black-2">
                  <strong>Sender Reputation:</strong> Maintain high email deliverability scores
                </li>
                <li style={{ marginBottom: "15px" }} className="text_2 text_black-2">
                  <strong>Lead Quality Validation:</strong> Verify lead email addresses before importing
                </li>
                <li className="text_2 text_black-2">
                  <strong>CRM Data Hygiene:</strong> Keep your CRM database clean and accurate
                </li>
              </ul>
            </div>
          </div>
        </div>
      </section>

      {/* FAQ SECTION */}
      <section className="flat-spacing-4">
        <div className="container">
          <div className="row">
            <div className="col-12">
              <FAQAccordion pageName="email-validator" />
            </div>
          </div>
        </div>
      </section>

      <ScrollTop />
      <Footer2 bgColor="background-black bg_green-4" />
    </>
  );
}